import { Schema } from "effect"

   // Channel types
   export const Channel = Schema.Literal("slack", "discord", "email", "push", "webhook")
   export type Channel = Schema.Schema.Type<typeof Channel>

   // Integration configuration schemas
   export const SlackConfig = Schema.Struct({
     webhookUrl: Schema.String.pipe(Schema.pattern(/^https:\/\/hooks\.slack\.com/)),
     channel: Schema.optional(Schema.String),
   })

   export const DiscordConfig = Schema.Struct({
     webhookUrl: Schema.String.pipe(Schema.pattern(/^https:\/\/discord\.com\/api\/webhooks/)),
   })

   export const EmailConfig = Schema.Struct({
     smtpHost: Schema.String,
     smtpPort: Schema.Number.pipe(Schema.int(), Schema.between(1, 65535)),
     fromAddress: Schema.String.pipe(Schema.pattern(/^[^@]+@[^@]+$/)),
     username: Schema.String,
     password: Schema.String,
   })

   export const WebhookConfig = Schema.Struct({
     url: Schema.String.pipe(Schema.pattern(/^https?:\/\//)),
     headers: Schema.optional(Schema.Record({ key: Schema.String, value: Schema.String })),
     secret: Schema.optional(Schema.String),
   })

   // Integration entity
   export const Integration = Schema.Struct({
     id: Schema.String,
     tenantId: Schema.String,
     channel: Channel,
     name: Schema.String.pipe(Schema.minLength(1), Schema.maxLength(100)),
     config: Schema.Union(SlackConfig, DiscordConfig, EmailConfig, WebhookConfig),
     enabled: Schema.Boolean,
     createdAt: Schema.Date,
     updatedAt: Schema.Date,
   })
   export type Integration = Schema.Schema.Type<typeof Integration>

   // Notification message
   export const NotificationMessage = Schema.Struct({
     id: Schema.String,
     tenantId: Schema.String,
     channel: Channel,
     priority: Schema.Literal("critical", "high", "normal", "low"),
     payload: Schema.Struct({
       title: Schema.String,
       body: Schema.String,
       metadata: Schema.optional(Schema.Record({ key: Schema.String, value: Schema.Unknown })),
     }),
   })
   export type NotificationMessage = Schema.Schema.Type<typeof NotificationMessage>

   // Error types as tagged errors
   export class SlackDeliveryError extends Schema.TaggedError<SlackDeliveryError>("SlackDeliveryError")({
     message: Schema.String,
     statusCode: Schema.optional(Schema.Number),
   }) {}

   export class DiscordDeliveryError extends Schema.TaggedError<DiscordDeliveryError>("DiscordDeliveryError")({
     message: Schema.String,
     statusCode: Schema.optional(Schema.Number),
   }) {}

   export class EmailDeliveryError extends Schema.TaggedError<EmailDeliveryError>("EmailDeliveryError")({
     message: Schema.String,
   }) {}

   export class RateLimitError extends Schema.TaggedError<RateLimitError>("RateLimitError")({
     retryAfter: Schema.Number,
   }) {}

   export class ConfigurationError extends Schema.TaggedError<ConfigurationError>("ConfigurationError")({
     message: Schema.String,
   }) {}

import { Context, Effect, Layer, Schedule } from "effect"
   import { HttpClient } from "@effect/platform"
   import { Integration, NotificationMessage, SlackDeliveryError } from "../schemas"

   export class SlackService extends Context.Tag("SlackService")<
     SlackService,
     {
       deliver: (integration: Integration, message: NotificationMessage) => Effect.Effect<{ success: boolean }, SlackDeliveryError>
     }
   >() {}

   export const SlackServiceLive = Layer.succeed(
     SlackService,
     SlackService.of({
       deliver: (integration, message) => {
         const slackPayload = {
           text: message.payload.title,
           blocks: [
             {
               type: "section",
               text: {
                 type: "mrkdwn",
                 text: `*${message.payload.title}*\n${message.payload.body}`,
               },
             },
           ],
         }

         return HttpClient.request.post(integration.config.webhookUrl).pipe(
           HttpClient.request.jsonBody(slackPayload),
           HttpClient.client.fetchOk,
           Effect.flatMap(() => Effect.succeed({ success: true })),
           Effect.retry(
             Schedule.exponential("1 second").pipe(
               Schedule.compose(Schedule.recurs(3)),
               Schedule.jittered
             )
           ),
           Effect.mapError((e) => new SlackDeliveryError({ message: e.message, statusCode: e.statusCode }))
         )
       },
     })
   )

import { Context, Effect, Layer } from "effect"
   import nodemailer from "nodemailer"
   import { Integration, NotificationMessage, EmailDeliveryError } from "../schemas"

   export class EmailService extends Context.Tag("EmailService")<
     EmailService,
     {
       deliver: (integration: Integration, message: NotificationMessage) => Effect.Effect<{ success: boolean }, EmailDeliveryError>
     }
   >() {}

   export const EmailServiceLive = Layer.effect(
     EmailService,
     Effect.gen(function* () {
       return EmailService.of({
         deliver: (integration, message) =>
           Effect.tryPromise({
             try: async () => {
               const transporter = nodemailer.createTransport({
                 host: integration.config.smtpHost,
                 port: integration.config.smtpPort,
                 auth: {
                   user: integration.config.username,
                   pass: integration.config.password,
                 },
               })
               await transporter.sendMail({
                 from: integration.config.fromAddress,
                 to: message.payload.metadata?.recipient || "default@example.com",
                 subject: message.payload.title,
                 text: message.payload.body,
               })
               return { success: true }
             },
             catch: (e) => new EmailDeliveryError({ message: String(e) }),
           }),
       })
     })
   )

import { Effect, Context, Layer } from "effect"
   import { MongoClient, Db } from "mongodb"
   import { Integration } from "../schemas"

   export class IntegrationRepository extends Context.Tag("IntegrationRepository")<
     IntegrationRepository,
     {
       findById: (id: string) => Effect.Effect<Integration | null, Error>
       findByTenant: (tenantId: string) => Effect.Effect<Integration[], Error>
       create: (integration: Integration) => Effect.Effect<Integration, Error>
       update: (id: string, data: Partial<Integration>) => Effect.Effect<Integration, Error>
       delete: (id: string) => Effect.Effect<void, Error>
     }
   >() {}

   export const IntegrationRepositoryLive = Layer.effect(
     IntegrationRepository,
     Effect.gen(function* () {
       const client = yield* Effect.promise(() => MongoClient.connect(process.env.MONGODB_URL!))
       const db = client.db("alerthub")
       const collection = db.collection<Integration>("integrations")

       return IntegrationRepository.of({
         findById: (id) =>
           Effect.tryPromise({
             try: () => collection.findOne({ id }),
             catch: (e) => new Error(String(e)),
           }),
         findByTenant: (tenantId) =>
           Effect.tryPromise({
             try: () => collection.find({ tenantId }).toArray(),
             catch: (e) => new Error(String(e)),
           }),
         create: (integration) =>
           Effect.tryPromise({
             try: async () => {
               await collection.insertOne(integration)
               return integration
             },
             catch: (e) => new Error(String(e)),
           }),
         update: (id, data) =>
           Effect.tryPromise({
             try: async () => {
               const result = await collection.findOneAndUpdate(
                 { id },
                 { $set: { ...data, updatedAt: new Date() } },
                 { returnDocument: "after" }
               )
               return result!
             },
             catch: (e) => new Error(String(e)),
           }),
         delete: (id) =>
           Effect.tryPromise({
             try: () => collection.deleteOne({ id }).then(() => {}),
             catch: (e) => new Error(String(e)),
           }),
       })
     })
   )

import { Effect, Stream, Schedule } from "effect"
   import { Kafka } from "kafkajs"
   import { NotificationMessage } from "../schemas"
   import { SlackService } from "../services/slack.service"
   import { IntegrationRepository } from "../repositories/integration.repository"

   export const createNotificationConsumer = Effect.gen(function* () {
     const kafka = new Kafka({ brokers: [process.env.KAFKA_BROKERS!] })
     const consumer = kafka.consumer({ groupId: "integration-service" })
     yield* Effect.promise(() => consumer.connect())
     yield* Effect.promise(() => consumer.subscribe({ topic: "alerthub.notifications.created" }))

     const messageStream = Stream.async<NotificationMessage, Error>((emit) => {
       consumer.run({
         eachMessage: async ({ message }) => {
           const payload = JSON.parse(message.value!.toString())
           emit.single(payload)
         },
       })
       return Effect.sync(() => consumer.disconnect())
     })

     return messageStream.pipe(
       Stream.mapEffect((message) =>
         Effect.gen(function* () {
           const repo = yield* IntegrationRepository
           const integrations = yield* repo.findByTenant(message.tenantId)
           const channelIntegration = integrations.find((i) => i.channel === message.channel && i.enabled)

           if (!channelIntegration) {
             return Effect.fail(new Error("No enabled integration found"))
           }

           const slack = yield* SlackService
           return yield* slack.deliver(channelIntegration, message)
         })
       ),
       Stream.runDrain
     )
   })

import { Elysia } from "elysia"
   import { Effect } from "effect"
   import { Integration } from "../schemas"
   import { IntegrationRepository } from "../repositories/integration.repository"
   import { SlackService, SlackServiceLive } from "../services/slack.service"
   import { IntegrationRepositoryLive } from "../repositories/integration.repository"

   export const integrationRoutes = new Elysia({ prefix: "/api/v1/integrations" })
     .post("/", async ({ body }) => {
       const program = Effect.gen(function* () {
         const repo = yield* IntegrationRepository
         return yield* repo.create(body as Integration)
       })
       return Effect.runPromise(program.pipe(Effect.provide(IntegrationRepositoryLive)))
     })
     .get("/", async ({ query }) => {
       const program = Effect.gen(function* () {
         const repo = yield* IntegrationRepository
         return yield* repo.findByTenant(query.tenantId as string)
       })
       return Effect.runPromise(program.pipe(Effect.provide(IntegrationRepositoryLive)))
     })
     .get("/:id", async ({ params }) => {
       const program = Effect.gen(function* () {
         const repo = yield* IntegrationRepository
         return yield* repo.findById(params.id)
       })
       return Effect.runPromise(program.pipe(Effect.provide(IntegrationRepositoryLive)))
     })
     .post("/:id/test", async ({ params, body }) => {
       const program = Effect.gen(function* () {
         const repo = yield* IntegrationRepository
         const integration = yield* repo.findById(params.id)
         if (!integration) return Effect.fail(new Error("Integration not found"))

         const slack = yield* SlackService
         return yield* slack.deliver(integration, body as any)
       })
       return Effect.runPromise(
         program.pipe(
           Effect.provide(IntegrationRepositoryLive),
           Effect.provide(SlackServiceLive)
         )
       )
     })

import { Elysia } from "elysia" import { Effect } from "effect" import { integrationRoutes } from "./routes/integration.routes" import { createNotificationConsumer } from "./consumers/notification.consumer"
const app = new Elysia() .use(integrationRoutes) .get("/health", () => ({ status: "ok" })) .listen(3000)
// Start Kafka consumer Effect.runPromise( createNotificationConsumer.pipe( Effect.catchAll((e) => Effect.sync(() => console.error("Consumer error:", e))) ) )
console.log(`Integration service running on port 3000`)
